import React from "react";

export default function CTA() {
  return (
    <section id="cta" className="text-center text-white py-5">
      <div className="container">
        <h2 className="fw-bold mb-3">Ready to Get Started?</h2>
        <p className="mb-4 mx-auto">
          Join hundreds of businesses that trust us. Let's build something great together.
        </p>
        <a href="#" className="btn fw-semibold px-4 py-2 rounded-pill btn-cta">
          Get In Touch
        </a>
      </div>
    </section>
  );
}
